using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;/// <summary>/// Bad case: Get EHR records for non-existent patient/// Expected: 200 OK with empty array or 404 Not Found/// </summary>public class EhrServiceTests_GetPatientEhrRecords_WithNonExistentPatient_ShouldReturnEmptyOrNotFound : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService"    };    [SkippableFact]    public async Task GetPatientEhrRecords_WithNonExistentPatient_ShouldReturnEmptyOrNotFound()    {        await AuthenticateAsDoctorAsync(EhrClient);        var fakePatientId = Guid.NewGuid();                var response = await GetWithRetryAsync(EhrClient, ApiEndpoints.Ehr.PatientRecords(fakePatientId));        Assert.True(            response.StatusCode == HttpStatusCode.OK ||             response.StatusCode == HttpStatusCode.NotFound,            $"Expected 200 or 404, got {response.StatusCode}");        if (response.StatusCode == HttpStatusCode.OK)        {            var json = await ReadJsonResponseAsync(response);            Assert.True(json.ValueKind == JsonValueKind.Array, "Should return array");        }    }}
